import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function homePage(){
    class HomePage extends React.Component{
        constructor(props){
            super(props);
            this.state = {
                value: 'Username'
            }
            this.handleChange = this.handleChange.bind(this);
            this.handleSubmit = this.handleSubmit.bind(this);
        }
        handleChange(event){
            this.setState({value: event.target.value})
        }
        handleSubmit(event){
            alert("Value" + this.state.value)
            event.preventDefault()
        }
    }    
    const name = (
        <div id = "main">
            <head>
                <title>Sign In/Sign UP</title>
            </head>
            <div id = "signin">
            <form onSubmit={this.handleSubmit}>
            <body>
            <h2>Login With Your Email Address</h2>
            <input type = "text" onChange = {this.handleChange} id = "username" placeholder = "Username"></input>
            <input type = "text" id = "password" placeholder = "Password"></input>
            <h2>Sign Up With Your Email Address</h2>
            <input type = "text" id = "emailaddress"></input>
            <input type = "text" id = "pass"></input>
                <br></br>
                <input type="submit" value="Submit" onClick = {HomePage}/>
            </body>
            </form>
            </div>
        </div>
    );
    ReactDOM.render(name, document.getElementById('root'))
}
setInterval(homePage, 1000)
